// Build a list of {owner, repo} from the search result + filter to repos updated in last 24h
const items = $json.data || [];
const cutoff = Date.now() - 24*60*60*1000;
const keep = [];
for (const r of items) {
  if (new Date(r.updated_at).getTime() >= cutoff) {
    keep.push({json: {owner: r.owner.login, repo: r.name, full: r.full_name, updated: r.updated_at}});
  }
}
return keep;

// Reduce all commits across all repos into a digest message
const cutoff = Date.now() - 24*60*60*1000;
const lines = [];
let repoCount = 0;
let commitCount = 0;

for (const item of $input.all()) {
  const commits = (item.json || []).filter(c => new Date(c.created || c.commit?.author?.date || 0).getTime() >= cutoff);
  if (!commits.length) continue;
  repoCount++;
  const meta = item.json[0]?.repository || {};
  const repoName = meta.full_name || 'unknown';
  lines.push(`**${repoName}** (${commits.length} commit${commits.length>1?'s':''})`);
  for (const c of commits.slice(0, 5)) {
    const msg = (c.commit?.message || c.message || '').split('\n')[0].slice(0, 90);
    const who = c.commit?.author?.name || c.author?.login || 'unknown';
    lines.push(`  • ${msg} — _${who}_`);
    commitCount++;
  }
  if (commits.length > 5) lines.push(`  • …and ${commits.length-5} more`);
}

let text;
if (!lines.length) {
  text = ':sleeping: No Gitea activity in the last 24 hours.';
} else {
  text = `:newspaper: **Daily Gitea digest** — ${commitCount} commits across ${repoCount} repo${repoCount>1?'s':''}\n\n${lines.join('\n')}`;
}

return [{json: {text}}];
